SELECT
  CASE
    WHEN m.id IS NULL THEN 'Não'
    ELSE 'Sim'
  END AS lead_existe,

  CASE
    WHEN m.id IS NULL THEN NULL
    WHEN m.lixeira = 1 THEN 'Sim'
    ELSE 'Não'
  END AS esta_na_lixeira,

  CASE
    WHEN m.id IS NULL THEN NULL
    WHEN EXISTS (
      SELECT 1
      FROM operacao o
      WHERE o.mailing_id = m.id
    )
    THEN 'Sim'
    ELSE 'Não'
  END AS tem_operacao,

  m.id AS mailing_id,
  m.clientes,
  m.empresa,
  m.whatsapp,
  m.status_contato,
  m.status_plano_acao,
  m.fup,

  CASE
    WHEN m.id IS NULL THEN 'Não'
    WHEN m.fup IS NULL OR m.fup = '' THEN 'Sim'
    WHEN DATE(m.fup) < CURDATE() THEN 'Sim'
    ELSE 'Não'
  END AS alterar_fup,

  m.email

FROM (SELECT 1) base

LEFT JOIN (
  SELECT *
  FROM mailing
  WHERE whatsapp IN (
    "{{ 
      (() => {
        const rawPhone = String(
          $('Webhook').first().json.body.sender.phone_number || ''
        );

        const phone = rawPhone.replace(/\D/g, '');
        let local = phone.startsWith('55') ? phone.slice(2) : phone;

        if (local.length === 11) {
          return `(${local.slice(0, 2)}) ${local.slice(2, 7)}-${local.slice(7)}`;
        }

        if (local.length === 10) {
          return `(${local.slice(0, 2)}) ${local.slice(2, 6)}-${local.slice(6)}`;
        }

        return '';
      })()
    }}",

    "{{ 
      (() => {
        const rawPhone = String(
          $('Webhook').first().json.body.sender.phone_number || ''
        );

        const phone = rawPhone.replace(/\D/g, '');
        let local = phone.startsWith('55') ? phone.slice(2) : phone;

        if (local.length === 11 && local.slice(2, 3) === '9') {
          local = local.slice(0, 2) + local.slice(3);
        }

        if (local.length === 10) {
          return `(${local.slice(0, 2)}) ${local.slice(2, 6)}-${local.slice(6)}`;
        }

        return '';
      })()
    }}"
  )
  ORDER BY id DESC
  LIMIT 1
) m ON 1 = 1;

